# 通过注解的方式

## 在配置文件配置数据库连接application.yml

~~~
server:
  port: 8000

spring:
  datasource:
    driver-class-name: com.mysql.cj.jdbc.Driver
    username: root
    password: 123456
    url: jdbc:mysql://127.0.0.1:3306/mall?characterEncoding=utf8&useSSL=false
mybatis:
  configuration:
    map-underscore-to-camel-case: true

~~~

## 定义CityMapper

~~~
import org.apache.ibatis.annotations.Mapper;
import org.apache.ibatis.annotations.Param;
import org.apache.ibatis.annotations.Select;

@Mapper
public interface CityMapper {
    @Select("SELECT * FROM CITY WHERE state = #{state}")
    City findByState(@Param("state") String state);
}
~~~

> 当数据库表特别多的时候,我们写一个interface的时候都需要加上`@Mapper`注解，这时候我们只需要在入口加上
>
> ~~~
> import org.mybatis.spring.annotation.MapperScan;
> import org.springframework.boot.SpringApplication;
> import org.springframework.boot.autoconfigure.SpringBootApplication;
> 
> @SpringBootApplication
> @MapperScan(basePackages = "com.github.example.mapper")
> public class Application {
>     public static void main(String[] args) {
>         SpringApplication.run(Application.class,args);
>     }
> }
> ~~~

