// sql 获取子类数据
function get_child_user_sql($uid){
    $sql = "SELECT * FROM  ".
    "(SELECT id,parent_id FROM users ORDER BY parent_id,id) as t,(SELECT @pv := {$uid}) as pv ".
    "WHERE find_in_set(parent_id, @pv) AND LENGTH(@pv := concat(@pv, ',', id))";
    return \think\Db::query($sql);
}
